import { db } from "./db";
import { chatChannels } from "@shared/schema";
import { eq } from "drizzle-orm";

const DEFAULT_CHANNELS = [
  { name: "general", description: "General discussion for all THE VOID members", category: "ecosystem", isDefault: true },
  { name: "announcements", description: "Official announcements from DarkWave Studios", category: "ecosystem", isDefault: false },
  { name: "darkwavestudios-support", description: "Support for DarkWave Studios products", category: "app-support", isDefault: false },
  { name: "garagebot-support", description: "Support for GarageBot.io", category: "app-support", isDefault: false },
  { name: "tlid-marketing", description: "Trust Layer ID marketing and updates", category: "app-support", isDefault: false },
  { name: "guardian-ai", description: "Guardian AI discussion and support", category: "app-support", isDefault: false },
];

export async function seedChatChannels() {
  try {
    for (const channel of DEFAULT_CHANNELS) {
      const existing = await db.select().from(chatChannels).where(eq(chatChannels.name, channel.name));
      if (existing.length === 0) {
        await db.insert(chatChannels).values(channel);
        console.log(`[Chat Seed] Created channel: #${channel.name}`);
      }
    }
    console.log("[Chat Seed] Channel seeding complete");
  } catch (err) {
    console.error("[Chat Seed] Error seeding channels:", err);
  }
}

client/src/hooks/use-subscription.ts.content:
import { useQuery } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";

interface SubscriptionStatus {
  tier: "free" | "premium";
  ventsUsedToday: number;
  ventsRemaining: number;
  status: string;
  currentPeriodEnd?: string;
  voidId?: string | null;
  isFounder?: boolean;
}

export function useSubscription(userId: number | null) {
  return useQuery<SubscriptionStatus>({
    queryKey: ["/api/subscription/status", userId],
    queryFn: async () => {
      if (!userId) return { tier: "free", ventsUsedToday: 0, ventsRemaining: 1, status: "free" };
      const res = await fetch(`/api/subscription/status?userId=${userId}`);
      if (!res.ok) throw new Error("Failed to fetch subscription");
      return res.json();
    },
    enabled: !!userId,
    refetchInterval: 30000,
  });
}

export async function createCheckoutSession(userId: number, userName?: string): Promise<string> {
  const res = await apiRequest("POST", "/api/stripe/create-checkout", { userId, userName });
  const data = await res.json();
  return data.url;
}

export async function createPortalSession(userId: number): Promise<string> {
  const res = await apiRequest("POST", "/api/stripe/create-portal", { userId });
  const data = await res.json();
  return data.url;
}

server/trustlayer-sso.ts.content:
import bcrypt from "bcryptjs";
import jwt from "jsonwebtoken";
import { db } from "./db";
import { chatUsers } from "@shared/schema";
import { eq } from "drizzle-orm";

const JWT_SECRET = process.env.JWT_SECRET || "dev-jwt-secret-change-me";
const SALT_ROUNDS = 12;
const TOKEN_EXPIRY = "7d";

const PASSWORD_REGEX = /^(?=.*[A-Z])(?=.*[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]).{8,}$/;

function generateTrustLayerId(): string {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substring(2, 10);
  return `tl-${timestamp}-${random}`;
}

function generateAvatarColor(): string {
  const colors = ["#06b6d4", "#8b5cf6", "#ec4899", "#f59e0b", "#10b981", "#3b82f6", "#ef4444", "#6366f1"];
  return colors[Math.floor(Math.random() * colors.length)];
}

export function signToken(userId: string, trustLayerId: string, voidId?: string | null): string {
  const payload: any = { userId, trustLayerId, iss: "trust-layer-sso" };
  if (voidId) payload.voidId = voidId;
  return jwt.sign(payload, JWT_SECRET, { expiresIn: TOKEN_EXPIRY });
}

export function verifyToken(token: string): { userId: string; trustLayerId: string; voidId?: string } | null {
  try {
    const decoded = jwt.verify(token, JWT_SECRET) as any;
    if (decoded.iss !== "trust-layer-sso") return null;
    return { userId: decoded.userId, trustLayerId: decoded.trustLayerId, voidId: decoded.voidId || undefined };
  } catch {
    return null;
  }
}

export function validatePassword(password: string): { valid: boolean; message: string } {
  if (!PASSWORD_REGEX.test(password)) {
    return {
      valid: false,
      message: "Password must be at least 8 characters with 1 uppercase letter and 1 special character.",
    };
  }
  return { valid: true, message: "" };
}

export async function registerUser(username: string, email: string, password: string, displayName: string) {
  const passwordCheck = validatePassword(password);
  if (!passwordCheck.valid) {
    return { success: false, error: passwordCheck.message };
  }

  const existing = await db.select().from(chatUsers).where(eq(chatUsers.username, username));
  if (existing.length > 0) {
    return { success: false, error: "Username already taken." };
  }

  const existingEmail = await db.select().from(chatUsers).where(eq(chatUsers.email, email));
  if (existingEmail.length > 0) {
    return { success: false, error: "Email already registered." };
  }

  const passwordHash = await bcrypt.hash(password, SALT_ROUNDS);
  const trustLayerId = generateTrustLayerId();
  const avatarColor = generateAvatarColor();

  const [user] = await db.insert(chatUsers).values({
    username,
    email: email.toLowerCase(),
    passwordHash,
    displayName,
    avatarColor,
    trustLayerId,
  }).returning();

  const token = signToken(user.id, trustLayerId, user.voidId);

  return {
    success: true,
    user: {
      id: user.id,
      username: user.username,
      displayName: user.displayName,
      email: user.email,
      avatarColor: user.avatarColor,
      role: user.role,
      trustLayerId: user.trustLayerId,
      voidId: user.voidId || null,
    },
    token,
  };
}

export async function loginUser(username: string, password: string) {
  const [user] = await db.select().from(chatUsers).where(eq(chatUsers.username, username));
  if (!user) {
    return { success: false, error: "Invalid username or password." };
  }

  const valid = await bcrypt.compare(password, user.passwordHash);
  if (!valid) {
    return { success: false, error: "Invalid username or password." };
  }

  await db.update(chatUsers).set({ isOnline: true, lastSeen: new Date() }).where(eq(chatUsers.id, user.id));

  const token = signToken(user.id, user.trustLayerId || "", user.voidId);

  return {
    success: true,
    user: {
      id: user.id,
      username: user.username,
      displayName: user.displayName,
      email: user.email,
      avatarColor: user.avatarColor,
      role: user.role,
      trustLayerId: user.trustLayerId,
      voidId: user.voidId || null,
    },
    token,
  };
}

export async function getUserFromToken(token: string) {
  const decoded = verifyToken(token);
  if (!decoded) return null;

  const [user] = await db.select().from(chatUsers).where(eq(chatUsers.id, decoded.userId));
  if (!user) return null;

  return {
    id: user.id,
    username: user.username,
    displayName: user.displayName,
    email: user.email,
    avatarColor: user.avatarColor,
    role: user.role,
    trustLayerId: user.trustLayerId,
    voidId: user.voidId || null,
  };
}

